  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Store form data in localStorage as backup
    const submissions = JSON.parse(localStorage.getItem('kapta_leads') || '[]');
    submissions.push({ ...formData, date: new Date().toISOString() });
